#include "perm.h"
#include <bits/stdc++.h>
using namespace std;
void init(int, int);
std::vector<int> perm(int);
int query(int, int);

const int N=3e4+10;

int tc,p[N][2],ans[N],f[N];

void init(int c, int t) {
    tc=c;
    return;
}

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

std::vector<int> perm(int n) {
    int l=0,r=0;
    p[n-1][0]=n;
    for(int i=0;i<=n;i++)
        f[i]=i;
    for(int i=n-2;i>=0;i--){
        p[i][0]=query(0,i);
        if(p[i][0]==0){
            l=r=i+1;
            break;
        }
    }
    for(int i=l;i;i--)
        p[i][1]=query(i,n-1);
    p[0][1]=n;
    f[l]=l+1;
    ans[l]=0;
    //printf("%d\n",l);
    for(int i=1;i<n;i++){
        if(p[l][1]>i && p[r][0]>i){
            int x=father(l);
            ans[x]=i;
            f[x]=father(x+1);
            //printf("%d\n",x);
        }else if(p[r][0]>i){
            int lt=0,rt=l-1;
            while(lt<rt){
                int mid=lt+rt+1>>1;
                if(p[mid][1]>i)
                    lt=mid;
                else
                    rt=mid-1;
            }
            ans[lt]=i;
            f[lt]=father(lt+1);
            l=lt;
            //printf("%d\n",lt);
        }else{
            int lt=r+1,rt=n-1;
            while(lt<rt){
                int mid=lt+rt>>1;
                if(p[mid][0]>i)
                    rt=mid;
                else
                    lt=mid+1;
            }
            ans[lt]=i;
            f[lt]=father(lt+1);
            r=lt;
            //printf("%d\n",lt);
        }
    }
    vector<int> res;
    res.clear();
    for(int i=0;i<n;i++)
        res.push_back(ans[i]);
    return res;
}
